```typescript
function createRichText(parent: cc.Node, x: number, y: number): void {
    const normal = cc.Label.createWithSystemFont('You earned ', 'Arial', 18);
    normal.setTextColor(cc.color(255, 255, 255));
    normal.setAnchorPoint(cc.p(0, 0.5));
    normal.setPosition(x, y);
