// Get a texture
const texture = cc.textureCache.addImage('res/sprite.png');

// Pixelated look (no interpolation) — great for pixel art
texture.setTexParameters(gl.NEAREST, gl.NEAREST, gl.CLAMP_TO_EDGE, gl.CLAMP_TO_EDGE);

