```typescript
const WeaponType = {
    NONE: 'none',
    SWORD: 'sword',
    AXE: 'axe',
    BOW: 'bow',
    STAFF: 'staff'
} as const;

type WeaponTypeValue = typeof WeaponType[keyof typeof WeaponType];

const WEAPON_SLOT = 'weapon_slot';

const WEAPON_ATTACHMENT_MAP: Record<WeaponTypeValue, string | null> = {
    [WeaponType.NONE]: null,
    [WeaponType.SWORD]: 'sword',
    [WeaponType.AXE]: 'axe',
    [WeaponType.BOW]: 'bow',
    [WeaponType.STAFF]: 'staff'
};

class WeaponSystem {
    private skel: sp.SkeletonAnimation;
    private currentWeapon: WeaponTypeValue = WeaponType.NONE;

    constructor(skel: sp.SkeletonAnimation) {
        this.skel = skel;
    }

    equipWeapon(weapon: WeaponTypeValue): void {
        const attachment = WEAPON_ATTACHMENT_MAP[weapon];
        this.skel.setAttachment(WEAPON_SLOT, attachment);
        this.currentWeapon = weapon;
    }

    unequipWeapon(): void {
        this.skel.setAttachment(WEAPON_SLOT, null);
        this.currentWeapon = WeaponType.NONE;
    }

    getCurrentWeapon(): WeaponTypeValue {
        return this.currentWeapon;
    }
}

// Usage:
const hero = new sp.SkeletonAnimation('res/hero/hero.json', 'res/hero/hero.atlas');
hero.setAnimation(0, 'idle', true);

const weapons = new WeaponSystem(hero);
weapons.equipWeapon(WeaponType.SWORD);  // shows sword
weapons.equipWeapon(WeaponType.BOW);    // switches to bow
weapons.unequipWeapon();                // hides weapon
```

`setAttachment` with `null` hides the attachment. The attachment names must match those defined in the Spine editor project for the given slot.

Use Cocos2d-x type checks to validate external data before using it:

```typescript
interface LevelConfig {
    name: string;
    enemies: { type: string; x: number; y: number }[];
    onComplete: () => void;
    metadata: { [key: string]: any };
}

function validateLevelConfig(raw: unknown): LevelConfig | null {
    if (!cc.isObject(raw)) {
        cc.error('Config must be an object');
        return null;
    }

    const config = raw as any;

    if (!cc.isString(config.name)) {
        cc.error('Config.name must be a string');
        return null;
    }

    if (!cc.isArray(config.enemies)) {
        cc.error('Config.enemies must be an array');
        return null;
    }

    for (let i = 0; i < config.enemies.length; i++) {
        const enemy = config.enemies[i];
        if (!cc.isObject(enemy)) {
            cc.error('Enemy at index', i, 'must be an object');
            return null;
        }
        if (!cc.isString(enemy.type) || !cc.isNumber(enemy.x) || !cc.isNumber(enemy.y)) {
            cc.error('Invalid enemy data at index', i);
            return null;
        }
    }

    if (config.onComplete && !cc.isFunction(config.onComplete)) {
        cc.error('Config.onComplete must be a function');
        return null;
    }

    return config as LevelConfig;
}

// Usage:
cc.loader.loadJson('res/level1.json', (err, data) => {
    if (err) return cc.error(err);
    const config = validateLevelConfig(data);
    if (config) {
        startLevel(config);
    }
});
```

