Returns a number identifying which mouse button was involved:

```typescript
cc.EventMouse.BUTTON_LEFT   = 0  // left click
cc.EventMouse.BUTTON_RIGHT  = 1  // right click
cc.EventMouse.BUTTON_MIDDLE = 2  // middle click (wheel press)
```

Usage:
```typescript
cc.eventManager.addListener({
    event: cc.EventListener.MOUSE,
    onMouseDown: (event: cc.EventMouse): void => {
        const button: number = event.getButton();
        switch (button) {
            case cc.EventMouse.BUTTON_LEFT:
                cc.log('Left click');
                break;
            case cc.EventMouse.BUTTON_RIGHT:
                cc.log('Right click');
                break;
            case cc.EventMouse.BUTTON_MIDDLE:
                cc.log('Middle click');
                break;
        }
    },
    onMouseUp: (event: cc.EventMouse): void => {
        if (event.getButton() === cc.EventMouse.BUTTON_LEFT) {
            cc.log('Left button released');
        }
    }
}, this);
```

Note: `getButton()` is relevant in `onMouseDown` and `onMouseUp`. In `onMouseMove`, no button may be pressed, so the value may not be meaningful.

Use scheduling to spawn bullets and actions to move them:

```typescript
class Turret extends cc.Sprite {
    private bulletSpeed = 400;

    onEnter(): void {
        super.onEnter();
        this.schedule(this.fireBullet, 0.5);
    }

    fireBullet(dt: number): void {
        const bullet = new cc.Sprite('bullet.png');
        bullet.setPosition(this.getPosition());
        bullet.setScale(0.5);
        this.getParent().addChild(bullet, -1);

        const targetY = cc.director.getWinSize().height + 20;
        const dist = targetY - bullet.y;
        const duration = dist / this.bulletSpeed;

        bullet.runAction(cc.sequence(
            cc.moveTo(duration, cc.p(bullet.x, targetY)),
            cc.removeSelf()
        ));
    }

    onExit(): void {
        this.unscheduleAllCallbacks();
        super.onExit();
    }
}
```

