```typescript
class BezierPathScene extends cc.Layer {
    onEnter(): void {
        super.onEnter();

        const p0 = cc.p(50, 100);
        const c1 = cc.p(100, 350);
        const c2 = cc.p(350, 50);
        const p3 = cc.p(430, 280);

        // 1. Visualize the path with DrawNode
        const draw = new cc.DrawNode();
        this.addChild(draw);

        // Control points and handles
        draw.drawDot(p0, 4, cc.color(0, 255, 0, 255));
        draw.drawDot(p3, 4, cc.color(255, 0, 0, 255));
        draw.drawDot(c1, 3, cc.color(255, 255, 0, 150));
        draw.drawDot(c2, 3, cc.color(255, 255, 0, 150));
        draw.drawSegment(p0, c1, 0.5, cc.color(255, 255, 255, 80));
        draw.drawSegment(p3, c2, 0.5, cc.color(255, 255, 255, 80));

        // The curve itself
        draw.drawCubicBezier(p0, c1, c2, p3, 50, 2, cc.color(0, 200, 255, 200));

        // 2. Move a sprite along the same bezier
        const sprite = new cc.Sprite('res/hero.png');
        sprite.setPosition(p0);
        this.addChild(sprite);

        const bezierConfig: cc.BezierConfig = [
            c1, c2, p3
        ];
        const moveAction = cc.bezierTo(2.0, bezierConfig);
        const repeatAction = cc.sequence(
            moveAction,
            cc.place(p0),
            cc.delayTime(0.5)
        ).repeatForever();

        sprite.runAction(repeatAction);
    }
}
```

The DrawNode renders the static path preview, while `cc.bezierTo` uses the same control points to animate the sprite. This lets players or designers see the trajectory visually.

instruction:
Find and fix the bug in this cc.LayerColor code:

```typescript
const overlay = new cc.LayerColor(cc.color(0, 0, 0, 128));
overlay.changeWidthAndHeight(480, 320);
this.addChild(overlay);

// Later, try to resize
overlay.changeWidth(240);
overlay.changeHeight(160);
overlay.setContentSize(480, 320);
```

output:
The bug is that `setContentSize` is called with two numbers directly, but `setContentSize` on `cc.Node` expects a `cc.Size` object, not two separate numbers.

**Fixed code:**
```typescript
const overlay = new cc.LayerColor(cc.color(0, 0, 0, 128));
overlay.changeWidthAndHeight(480, 320);
this.addChild(overlay);

// Later, resize — use one approach, not both
// Option 1: LayerColor-specific methods
overlay.changeWidthAndHeight(240, 160);

// Option 2: cc.Node's setContentSize with cc.size
overlay.setContentSize(cc.size(480, 320));
```

Additionally, calling `changeWidth` then `changeHeight` then `setContentSize` is redundant — the last call overwrites the first two. Use either `changeWidthAndHeight` or `setContentSize(cc.size(...))`, not both.

