```typescript
class ScreenFade {
    private overlay: cc.LayerColor;
    private parent: cc.Node;

    constructor(parent: cc.Node) {
        this.parent = parent;
        this.overlay = new cc.LayerColor(cc.color(0, 0, 0, 0));
        this.overlay.setContentSize(cc.director.getWinSize());
        this.overlay.setLocalZOrder(9999);
        this.parent.addChild(this.overlay);
    }

    fadeOut(duration: number, callback: () => void): void {
        this.overlay.setOpacity(0);
        this.overlay.runAction(
            cc.sequence(
                cc.fadeTo(duration, 255),
                cc.callFunc(callback)
            )
        );
    }

    fadeIn(duration: number): void {
        this.overlay.setOpacity(255);
        this.overlay.runAction(cc.fadeTo(duration, 0));
    }
}

// Usage:
const fade = new ScreenFade(this);
fade.fadeOut(0.5, () => {
    // Load next scene
    cc.director.runScene(new NextScene());
    fade.fadeIn(0.5);
});
```

The overlay starts fully transparent (alpha 0). `fadeOut` animates opacity to 255 (black), then triggers the callback. `fadeIn` animates from 255 back to 0. Using `cc.fadeTo` with `cc.sequence` and `cc.callFunc` chains the actions smoothly.

Use `cc.eventManager.removeCustomListeners`:

```typescript
cc.eventManager.removeCustomListeners(customEventName: string | number): void
```

This removes ALL listeners registered for the given custom event name, regardless of which object registered them.

```typescript
// Register multiple listeners for the same event
const listener1 = cc.eventManager.addCustomListener('level:complete', (event) => {
    cc.log('Listener 1: show fireworks');
});

const listener2 = cc.eventManager.addCustomListener('level:complete', (event) => {
    cc.log('Listener 2: update progress');
});

// Remove BOTH listeners at once
cc.eventManager.removeCustomListeners('level:complete');

// Alternatively, remove individually:
// cc.eventManager.removeListener(listener1);
// cc.eventManager.removeListener(listener2);
```

Use `removeCustomListeners` when you want to ensure no listeners remain for an event (e.g., during scene cleanup). Use `removeListener` with a specific reference when you need fine-grained control over which listener to remove.

```typescript
class SpriteProgressBar extends cc.Node {
    private _bgSprite: cc.Sprite;
    private _fillSprite: cc.Sprite;
    private _fullWidth: number;
    private _fullRect: cc.Rect;

    constructor(bgFrame: string, fillFrame: string) {
        super();

        this._bgSprite = new cc.Sprite(cc.spriteFrameCache.getSpriteFrame(bgFrame));
        this.addChild(this._bgSprite, 0);

        this._fillSprite = new cc.Sprite(cc.spriteFrameCache.getSpriteFrame(fillFrame));
        this._fillSprite.setAnchorPoint(cc.p(0, 0.5));
        const bgSize = this._bgSprite.getContentSize();
        this._fillSprite.setPosition(-bgSize.width / 2, 0);
        this.addChild(this._fillSprite, 1);

        this._fullRect = this._fillSprite.getTextureRect();
        this._fullWidth = this._fullRect.width;
    }

    setProgress(ratio: number): void {
        const clamped = Math.max(0, Math.min(1, ratio));
        const newWidth = Math.floor(this._fullWidth * clamped);
        this._fillSprite.setTextureRect(
            cc.rect(this._fullRect.x, this._fullRect.y, newWidth, this._fullRect.height)
        );
    }
}

// Usage:
cc.spriteFrameCache.addSpriteFrames('res/ui.plist', 'res/ui.png');
const bar = new SpriteProgressBar('bar_bg.png', 'bar_fill.png');
bar.setPosition(240, 280);
this.addChild(bar);
bar.setProgress(0.65); // 65%
```

This works by shrinking the texture rect of the fill sprite, effectively cropping it from the right.

The key difference is the number of control points:

- **Quadratic Bezier** (`drawQuadBezier`): Has 1 control point. Produces simpler curves.
- **Cubic Bezier** (`drawCubicBezier`): Has 2 control points. Produces more complex, S-shaped curves.

Signatures:
```typescript
// Quadratic: origin -> 1 control -> destination
draw.drawQuadBezier(
    origin: cc.Point, control: cc.Point, destination: cc.Point,
    segments: number, lineWidth: number, color?: cc.Color
): void

// Cubic: origin -> 2 controls -> destination
draw.drawCubicBezier(
    origin: cc.Point, control1: cc.Point, control2: cc.Point,
    destination: cc.Point, segments: number, lineWidth: number, color?: cc.Color
): void
```

Example comparison:
```typescript
const draw = new cc.DrawNode();
this.addChild(draw);

// Simple arc (quadratic)
draw.drawQuadBezier(cc.p(0, 0), cc.p(100, 200), cc.p(200, 0), 30, 2, cc.color(255, 0, 0, 255));

// S-curve (cubic)
draw.drawCubicBezier(cc.p(0, 0), cc.p(50, 200), cc.p(150, -100), cc.p(200, 100), 30, 2, cc.color(0, 0, 255, 255));
```

Access the event dispatcher for adding/removing listeners:

```typescript
const sprite = new cc.Sprite('interactive.png');
sprite.setPosition(240, 160);
this.addChild(sprite);

// Get the event dispatcher
const dispatcher = sprite.getEventDispatcher();
// In practice, use cc.eventManager (same global dispatcher):

const touchListener = cc.EventListener.create({
    event: cc.EventListener.TOUCH_ONE_BY_ONE,
    swallowTouches: true,
    onTouchBegan: (touch: cc.Touch, event: cc.Event): boolean => {
        const target = event.getCurrentTarget();
        const localPt = target.convertTouchToNodeSpace(touch);
        const rect = cc.rect(0, 0, target.width, target.height);
        return cc.rectContainsPoint(rect, localPt);
    },
    onTouchMoved: (touch: cc.Touch, event: cc.Event): void => {
        const target = event.getCurrentTarget();
        const delta = touch.getDelta();
        target.x += delta.x;
        target.y += delta.y;
    }
});

cc.eventManager.addListener(touchListener, sprite);
```
